136	function getCurrentModelLabel(ctx: any): string {
137	  if (typeof ctx?.model === "string" && ctx.model.trim()) return ctx.model.trim();
138	  if (ctx?.model?.provider && ctx?.model?.id) return `${ctx.model.provider}/${ctx.model.id}`;
139	
140	  const branch = ctx?.sessionManager?.getBranch?.();
141	  if (Array.isArray(branch)) {
142	    for (let index = branch.length - 1; index >= 0; index -= 1) {
143	      const entry = branch[index];
144	      if (entry?.type === "model_change" && entry.provider && entry.modelId) {
145	        return `${entry.provider}/${entry.modelId}`;
146	      }
147	    }
148	  }
149	
150	  return "not set";
151	}
