203	function registerToolGroup(pi: any, group: typeof ALL_TOOL_GROUPS[number]): void {
204	  for (const def of group.definitions) {
205	    const evolvedDef = globalToolRegistry.getActiveDefinition(def.name) ?? def;
206	    pi.registerTool({
207	      name: evolvedDef.name,
208	      label: evolvedDef.name.replace(/_/g, " "),
