210	      parameters: evolvedDef.parameters,
211	      async execute(_toolCallId: string, params: any, _signal: any, _onUpdate: any, ctx: any): Promise<{ content: Array<{ type: string; text: string }> }> {
212	        try {
213	          const result = await group.execute(ctx.cwd, def.name, params);
214	          return { content: [{ type: "text", text: result }] };
215	        } catch (err) {
216	          return { content: [{ type: "text", text: `Error: ${err instanceof Error ? err.message : String(err)}` }] };
217	        }
218	      }
219	    });
220	  }
221	}
