223	function createChrysalisWelcomeComponent(pi: any, ctx: any, state: Awaited<ReturnType<typeof loadProfileState>>, evolution: Awaited<ReturnType<typeof loadEvolutionState>>): (tui: any, theme: any) => any {
224	  const registeredToolCount = ALL_TOOL_GROUPS.reduce((sum, group) => sum + group.definitions.length, 0);
225	  const commandCount = CHRYSALIS_COMMAND_SECTIONS.reduce((sum, section) => sum + section.commands.length, 0);
226	  const evolutionSummary = summarizeEvolutionState(evolution);
227	
228	  return (_tui: any, theme: any): any => {
229	    const t = theme.fg.bind(theme);
230	    const b = theme.bold.bind(theme);
231	    const border = (text: string) => t("borderMuted", text);
232	    const dim = (text: string) => t("dim", text);
233	    const accent = (text: string) => t("accent", text);
234	    const heading = (text: string) => b(t("mdHeading", text));
235	    const text = (value: string) => t("text", value);
236	
237	    return {
238	      render(width: number): string[] {
239	        const maxWidth = Math.max(width - 2, 1);
240	        const cardWidth = Math.min(maxWidth, 122);
241	        const innerWidth = Math.max(cardWidth - 2, 1);
242	        const contentWidth = Math.max(innerWidth - 2, 1);
243	        const outerPad = " ".repeat(Math.max(0, Math.floor((width - cardWidth) / 2)));
244	        const lines: string[] = [];
245	        const push = (line: string) => lines.push(`${outerPad}${line}`);
246	        const row = (content: string) => `${border("│")} ${padVisible(content, contentWidth)} ${border("│")}`;
247	        const emptyRow = () => `${border("│")}${" ".repeat(innerWidth)}${border("│")}`;
248	        const separator = () => `${border("├")}${border("─".repeat(innerWidth))}${border("┤")}`;
249	        const useWideLayout = contentWidth >= 74;
250	
251	        push("");
252	        if (cardWidth >= 74) {
253	          const logoWidth = Math.max(...CHRYSALIS_ASCII_LOGO.map(line => line.length));
254	          const logoPad = " ".repeat(Math.max(0, Math.floor((cardWidth - logoWidth) / 2)));
255	          const palette = ["accent", "accent", "mdHeading", "mdHeading", "text", "text"];
256	          for (let index = 0; index < CHRYSALIS_ASCII_LOGO.length; index += 1) {
257	            push(b(t(palette[index] ?? "text", `${logoPad}${CHRYSALIS_ASCII_LOGO[index]}`)));
258	          }
259	          push("");
260	        }
261	
262	        const versionTag = ` v${CHRYSALIS_VERSION} `;
263	        const versionGap = Math.max(0, innerWidth - versionTag.length);
264	        const versionLeft = Math.floor(versionGap / 2);
265	        push(
266	          border(`╭${"─".repeat(versionLeft)}`) +
267	            dim(versionTag) +
268	            border(`${"─".repeat(versionGap - versionLeft)}╮`),
269	        );
270	
271	        if (useWideLayout) {
272	          const leftWidth = Math.min(40, Math.floor(contentWidth * 0.36));
273	          const dividerWidth = 3;
274	          const rightWidth = contentWidth - leftWidth - dividerWidth;
275	          const leftValueWidth = Math.max(1, leftWidth - 11);
276	          const commandNameWidth = 26;
277	          const commandDescWidth = Math.max(12, rightWidth - commandNameWidth - 2);
278	          const leftLines: string[] = [""];
279	          const rightLines: string[] = ["", heading("Chrysalis Workflows")];
280	          const leftLabel = (label: string, value: string, color: "text" | "dim") => {
281	            const wrapped = wrapWords(value, leftValueWidth);
282	            leftLines.push(`${dim(label.padEnd(10))} ${color === "text" ? text(wrapped[0]!) : dim(wrapped[0]!)}`);
283	            for (const line of wrapped.slice(1)) {
284	              leftLines.push(`${" ".repeat(11)}${color === "text" ? text(line) : dim(line)}`);
285	            }
286	          };
287	          const listBlock = (label: string, values: string[]) => {
288	            if (values.length === 0) return;
289	            leftLines.push("");
290	            leftLines.push(accent(b(label)));
291	            for (const value of values) {
292	              for (const line of wrapWords(value, leftWidth)) {
293	                leftLines.push(dim(line));
294	              }
295	            }
296	          };
297	
298	          leftLabel("model", getCurrentModelLabel(ctx), "text");
299	          leftLabel("directory", formatHeaderPath(ctx.cwd), "text");
300	          leftLabel("session", getSessionLabel(ctx), "dim");
301	          leftLabel("profile", state.activeProfile, "text");
302	          leftLines.push("");
303	          leftLines.push(dim(`${pi.getAllTools?.().length ?? registeredToolCount} tools · ${commandCount} commands`));
304	          listBlock("Purpose", CHRYSALIS_SUBTITLE_LINES);
305	          listBlock("Evolution", evolutionSummary.slice(2, 6));
306	          listBlock("Last Activity", [truncatePlain(summarizeLastActivity(ctx), leftWidth * 2)].filter(Boolean));
307	
308	          for (const section of CHRYSALIS_COMMAND_SECTIONS) {
309	            rightLines.push("");
310	            rightLines.push(accent(b(section.title)));
311	            for (const command of section.commands) {
312	              const wrapped = wrapWords(command.description, commandDescWidth);
313	              rightLines.push(`${accent(command.usage.padEnd(commandNameWidth))}${dim(wrapped[0]!)}`);
314	              for (const line of wrapped.slice(1)) {
315	                rightLines.push(`${" ".repeat(commandNameWidth)}${dim(line)}`);
316	              }
317	            }
318	          }
319	
320	          const maxRows = Math.max(leftLines.length, rightLines.length);
321	          for (let index = 0; index < maxRows; index += 1) {
322	            push(row(
323	              `${padVisible(leftLines[index] ?? "", leftWidth)}` +
324	              `${border(" │ ")}` +
325	              `${padVisible(rightLines[index] ?? "", rightWidth)}`,
326	            ));
327	          }
328	        } else {
329	          push(emptyRow());
330	          push(row(heading(centerPlain(CHRYSALIS_SUBTITLE_LINES[0] ?? "Chrysalis", contentWidth))));
331	          push(row(dim(centerPlain(`profile: ${state.activeProfile}`, contentWidth))));
332	          push(row(dim(centerPlain(`${pi.getAllTools?.().length ?? registeredToolCount} tools · ${commandCount} commands`, contentWidth))));
333	          push(emptyRow());
334	          push(separator());
335	          for (const section of CHRYSALIS_COMMAND_SECTIONS) {
336	            push(row(accent(b(section.title))));
337	            for (const command of section.commands) {
338	              const descWidth = Math.max(1, contentWidth - 26);
339	              push(row(`${accent(command.usage.padEnd(25))}${dim(truncatePlain(command.description, descWidth))}`));
340	            }
341	          }
342	        }
343	
344	        push(border(`╰${"─".repeat(innerWidth)}╯`));
345	        push("");
346	        return lines;
347	      },
348	      invalidate(): void {},
349	      dispose(): void {}
350	    };
351	  };
352	}
